database_changes.migration:
-- Add flaky indicator to test_results ALTER TABLE test_results ADD COLUMN IF NOT EXISTS is_flaky BOOLEAN DEFAULT false;
-- Create index for flaky tests CREATE INDEX IF NOT EXISTS idx_test_results_flaky ON test_results(is_flaky) WHERE is_flaky = true;
-- Create flakiness history tracking table CREATE TABLE IF NOT EXISTS test_flakiness_history ( id SERIAL PRIMARY KEY, test_signature TEXT NOT NULL UNIQUE, test_name TEXT NOT NULL, test_file TEXT NOT NULL, total_runs INTEGER DEFAULT 0, flaky_runs INTEGER DEFAULT 0, passed_runs INTEGER DEFAULT 0, failed_runs INTEGER DEFAULT 0, flakiness_rate DECIMAL(5,2) DEFAULT 0, avg_duration_ms INTEGER DEFAULT 0, last_flaky_at TIMESTAMP WITH TIME ZONE, last_passed_at TIMESTAMP WITH TIME ZONE, last_failed_at TIMESTAMP WITH TIME ZONE, first_seen_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW(), updated_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT NOW() );
-- Indexes for efficient queries CREATE INDEX IF NOT EXISTS idx_flakiness_rate ON test_flakiness_history(flakiness_rate DESC); CREATE INDEX IF NOT EXISTS idx_flakiness_flaky_runs ON test_flakiness_history(flaky_runs DESC); CREATE INDEX IF NOT EXISTS idx_flakiness_updated ON test_flakiness_history(updated_at DESC);
-- Backfill is_flaky for existing records UPDATE test_results SET is_flaky = true WHERE retry_count > 0 AND status = 'passed';
-- Backfill flakiness history from existing data INSERT INTO test_flakiness_history ( test_signature, test_name, test_file, total_runs, flaky_runs, passed_runs, failed_runs, flakiness_rate, avg_duration_ms, last_flaky_at, last_passed_at, last_failed_at, first_seen_at, updated_at ) SELECT COALESCE(test_signature, MD5(test_file || '::' || test_name)) as test_signature, test_name, test_file, COUNT(*) as total_runs, COUNT(*) FILTER (WHERE retry_count > 0 AND status = 'passed') as flaky_runs, COUNT(*) FILTER (WHERE status = 'passed') as passed_runs, COUNT(*) FILTER (WHERE status = 'failed') as failed_runs, CASE WHEN COUNT(*) FILTER (WHERE status = 'passed') > 0 THEN ROUND( COUNT(*) FILTER (WHERE retry_count > 0 AND status = 'passed')::decimal / COUNT(*) FILTER (WHERE status = 'passed') * 100, 2 ) ELSE 0 END as flakiness_rate, ROUND(AVG(duration_ms)) as avg_duration_ms, MAX(started_at) FILTER (WHERE retry_count > 0 AND status = 'passed') as last_flaky_at, MAX(started_at) FILTER (WHERE status = 'passed') as last_passed_at, MAX(started_at) FILTER (WHERE status = 'failed') as last_failed_at, MIN(started_at) as first_seen_at, NOW() as updated_at FROM test_results GROUP BY test_name, test_file, test_signature ON CONFLICT (test_signature) DO UPDATE SET total_runs = EXCLUDED.total_runs, flaky_runs = EXCLUDED.flaky_runs, passed_runs = EXCLUDED.passed_runs, failed_runs = EXCLUDED.failed_runs, flakiness_rate = EXCLUDED.flakiness_rate, avg_duration_ms = EXCLUDED.avg_duration_ms, last_flaky_at = EXCLUDED.last_flaky_at, last_passed_at = EXCLUDED.last_passed_at, last_failed_at = EXCLUDED.last_failed_at, updated_at = NOW();

backend.types:

// Add to TestResult interface
export interface TestResult {
  // ... existing fields
  is_flaky?: boolean;
}

// New interface for flakiness data
export interface TestFlakinessHistory {
  id: number;
  test_signature: string;
  test_name: string;
  test_file: string;
  total_runs: number;
  flaky_runs: number;
  passed_runs: number;
  failed_runs: number;
  flakiness_rate: number;
  avg_duration_ms: number;
  last_flaky_at: string | null;
  last_passed_at: string | null;
  last_failed_at: string | null;
  first_seen_at: string;
  updated_at: string;
}

// Flakiness summary for dashboard
export interface FlakinessSummary {
  total_flaky_tests: number;
  avg_flakiness_rate: number;
  most_flaky_tests: TestFlakinessHistory[];
}

database_functions.function:

// Check if a test result is flaky
export function isTestFlaky(retryCount: number, status: string): boolean {
  return retryCount > 0 && status === 'passed';
}


// Get flakiest tests
export async function getFlakiestTests(
  limit: number = 10,
  minRuns: number = 5
): Promise<TestFlakinessHistory[]> {
  const sql = getSql();

  const results = await sql`
    SELECT *
    FROM test_flakiness_history
    WHERE total_runs >= ${minRuns}
      AND flaky_runs > 0
    ORDER BY flakiness_rate DESC, flaky_runs DESC
    LIMIT ${limit}
  `;

  return results as TestFlakinessHistory[];
}


// Get flakiness summary for dashboard
export async function getFlakinessSummary(): Promise<FlakinessSummary> {
  const sql = getSql();

  const summaryResult = await sql`
    SELECT
      COUNT(*) FILTER (WHERE flaky_runs > 0) as total_flaky_tests,
      COALESCE(AVG(flakiness_rate) FILTER (WHERE flaky_runs > 0), 0) as avg_flakiness_rate
    FROM test_flakiness_history
    WHERE total_runs >= 5
  `;

  const topFlaky = await getFlakiestTests(5);

  return {
    total_flaky_tests: Number(summaryResult[0].total_flaky_tests),
    avg_flakiness_rate: Number(summaryResult[0].avg_flakiness_rate),
    most_flaky_tests: topFlaky
  };
}


// Get flakiness info for a specific test
export async function getTestFlakiness(
  testSignature: string
): Promise<TestFlakinessHistory | null> {
  const sql = getSql();

  const results = await sql`
    SELECT *
    FROM test_flakiness_history
    WHERE test_signature = ${testSignature}
  `;

  return results[0] as TestFlakinessHistory || null;
}

api_routes.route:

import { getFlakinessSummary, getFlakiestTests } from "@/lib/db";
import { NextRequest, NextResponse } from "next/server";

export const dynamic = "force-dynamic";

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const limit = parseInt(searchParams.get("limit") || "10");
    const minRuns = parseInt(searchParams.get("minRuns") || "5");

    const [summary, flakiestTests] = await Promise.all([
      getFlakinessSummary(),
      getFlakiestTests(limit, minRuns)
    ]);

    return NextResponse.json({
      summary,
      tests: flakiestTests
    });
  } catch (error) {
    console.error("Error fetching flakiness data:", error);
    return NextResponse.json(
      { error: "Failed to fetch flakiness data" },
      { status: 500 }
    );
  }
}

components.component:

import { Badge } from "@/components/ui/badge";
import {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "@/components/ui/tooltip";
import { AlertTriangle } from "lucide-react";

interface FlakyBadgeProps {
  flakinessRate?: number;
  flakyRuns?: number;
  totalRuns?: number;
  showTooltip?: boolean;
}

export function FlakyBadge({
  flakinessRate,
  flakyRuns,
  totalRuns,
  showTooltip = true,
}: FlakyBadgeProps) {
  if (!flakinessRate || flakinessRate === 0) {
    return null;
  }

  const badge = (
    <Badge
      variant="outline"
      className="bg-amber-500/10 text-amber-600 border-amber-500/20 gap-1"
    >
      <AlertTriangle className="h-3 w-3" />
      Flaky {flakinessRate.toFixed(0)}%
    </Badge>
  );

  if (!showTooltip) {
    return badge;
  }

  return (
    <TooltipProvider>
      <Tooltip>
        <TooltipTrigger asChild>{badge}</TooltipTrigger>
        <TooltipContent>
          <p>
            This test was flaky in {flakyRuns} of {totalRuns} runs
          </p>
          <p className="text-xs text-muted-foreground">
            Flaky = passed after retry
          </p>
        </TooltipContent>
      </Tooltip>
    </TooltipProvider>
  );
}


"use client";

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { AlertTriangle, FileCode } from "lucide-react";
import { FlakyBadge } from "./flaky-badge";

interface TestFlakinessHistory {
  test_signature: string;
  test_name: string;
  test_file: string;
  total_runs: number;
  flaky_runs: number;
  flakiness_rate: number;
  last_flaky_at: string | null;
}

interface FlakinessSummary {
  total_flaky_tests: number;
  avg_flakiness_rate: number;
}

export function FlakiestTestsCard() {
  const [data, setData] = useState<{
    summary: FlakinessSummary;
    tests: TestFlakinessHistory[];
  } | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    async function fetchData() {
      try {
        const response = await fetch("/api/flakiness?limit=5");
        const json = await response.json();
        setData(json);
      } catch (error) {
        console.error("Failed to fetch flakiness data:", error);
      } finally {
        setLoading(false);
      }
    }

    fetchData();
  }, []);

  if (loading) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <AlertTriangle className="h-5 w-5 text-amber-500" />
            Flakiest Tests
          </CardTitle>
        </CardHeader>
        <CardContent>
          <div className="space-y-3">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="h-12 bg-muted animate-pulse rounded" />
            ))}
          </div>
        </CardContent>
      </Card>
    );
  }

  if (!data || data.tests.length === 0) {
    return (
      <Card>
        <CardHeader>
          <CardTitle className="flex items-center gap-2">
            <AlertTriangle className="h-5 w-5 text-amber-500" />
            Flakiest Tests
          </CardTitle>
        </CardHeader>
        <CardContent>
          <p className="text-muted-foreground text-sm">
            No flaky tests detected yet. Great job!
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <Card>
      <CardHeader>
        <CardTitle className="flex items-center justify-between">
          <span className="flex items-center gap-2">
            <AlertTriangle className="h-5 w-5 text-amber-500" />
            Flakiest Tests
          </span>
          <Badge variant="secondary">
            {data.summary.total_flaky_tests} flaky
          </Badge>
        </CardTitle>
      </CardHeader>
      <CardContent>
        <div className="space-y-3">
          {data.tests.map((test) => (
            <div
              key={test.test_signature}
              className="flex items-start justify-between gap-2 p-2 rounded-lg hover:bg-muted/50"
            >
              <div className="flex-1 min-w-0">
                <p className="font-medium text-sm truncate">{test.test_name}</p>
                <p className="text-xs text-muted-foreground flex items-center gap-1">
                  <FileCode className="h-3 w-3" />
                  <span className="truncate">{test.test_file}</span>
                </p>
              </div>
              <div className="flex flex-col items-end gap-1">
                <FlakyBadge
                  flakinessRate={test.flakiness_rate}
                  flakyRuns={test.flaky_runs}
                  totalRuns={test.total_runs}
                />
                <span className="text-xs text-muted-foreground">
                  {test.flaky_runs}/{test.total_runs} runs
                </span>
              </div>
            </div>
          ))}
        </div>
      </CardContent>
    </Card>
  );
}

